+        data_cursor -= root_inode.len();
+        write_btrfs_leaf_item(
+            &mut image,
+            fs_leaf,
+            item_idx,
+            256,
+            BTRFS_ITEM_INODE_ITEM,
+            0,
+            data_cursor as u32,
+            root_inode.len() as u32,
