+                BTRFS_ITEM_INODE_ITEM,
+                0,
+                data_cursor as u32,
+                child_inode.len() as u32,
+            );
+            image[fs_leaf + data_cursor..fs_leaf + data_cursor + child_inode.len()]
+                .copy_from_slice(&child_inode);
+            item_idx += 1;
+        }
